import { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import API_URL from "../api"; 

function CapsuleDetail() {
  const { id } = useParams();
  const [capsule, setCapsule] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchCapsuleDetails = async () => {
      try {
        const token = localStorage.getItem("token"); 
        const response = await fetch(`${API_URL}/api/memoryhaven/${id}`, {
          headers: {
            Authorization: `Bearer ${token}`, 
          },
        });

        if (!response.ok) {
          throw new Error("Failed to fetch capsule details.");
        }

        const data = await response.json();
        setCapsule(data);
      } catch (error) {
        console.error("Error fetching capsule details:", error);
        setError(error.message);
      } finally {
        setLoading(false);
      }
    };

    fetchCapsuleDetails();
  }, [id]);

  return (
    <div>
      <h1>Capsule Details</h1>
      {loading ? (
        <p>Loading...</p>
      ) : error ? (
        <p>Error: {error}</p>
      ) : capsule ? (
        <div>
          <h2>{capsule.title}</h2>
          <p>{capsule.description}</p>
          <p>Created on: {new Date(capsule.createdAt).toLocaleDateString()}</p>

          {/* Display Media */}
          {capsule.media && capsule.media.length > 0 && (
            <div>
              <h3>Attached Media:</h3>
              {capsule.media.map((mediaPath, index) => {
                const fullPath = mediaPath.startsWith("http") ? mediaPath : `${API_URL}${mediaPath}`;

                return (
                  <div key={index} style={{ marginBottom: "10px", display: "flex", alignItems: "center", gap: "10px" }}>
                    {mediaPath.endsWith(".mp4") ? (
                      <>
                        <video controls src={fullPath} style={{ maxWidth: "120px", height: "auto" }} />
                        <a href={fullPath} target="_blank" rel="noopener noreferrer">Watch full video</a>
                      </>
                    ) : mediaPath.endsWith(".mp3") ? (
                      <>
                        <audio controls src={fullPath} style={{ width: "100px" }} />
                        <a href={fullPath} target="_blank" rel="noopener noreferrer">Listen to full audio</a>
                      </>
                    ) : (
                      <>
                        <img src={fullPath} alt="Memory Media" style={{ width: "80px", height: "80px", objectFit: "cover", borderRadius: "8px" }} />
                        <a href={fullPath} target="_blank" rel="noopener noreferrer">View full image</a>
                      </>
                    )}
                  </div>
                );
              })}
            </div>
          )}

        </div>
      ) : (
        <p>Capsule not found.</p>
      )}
    </div>
  );
}

export default CapsuleDetail;
